    79→#define _REAL(func, ...) real##_##func(__VA_ARGS__)
    80→#define DEFINE__REAL(ret_type, func, ...)                              \
    81→  static ret_type (*real_##func)(__VA_ARGS__) = NULL;                  \
    82→  if (!real_##func) {                                                  \
    83→    real_##func = (ret_type(*)(__VA_ARGS__))GetRealLibcAddress(#func); \
    84→  }                                                                    \
