    92→
    93→#  if !defined(_LP64) && _FILE_OFFSET_BITS == 64
    94→#    define _REAL64(func) _##func##64
    95→#  else
    96→#    define _REAL64(func) _REAL(func)
    97→#  endif
    98→#  define DEFINE__REAL64(ret_type, func, ...) \
    99→    extern "C" ret_type _REAL64(func)(__VA_ARGS__)
