   101→DEFINE__REAL64(void *, mmap, void *a, size_t b, int c, int d, int e, off_t f);
   102→DEFINE__REAL(int, munmap, void *a, size_t b);
   103→DEFINE__REAL(int, mprotect, void *a, size_t b, int c);
   104→#endif
